const ADD_POST = "ADD-POST";
const ADD_MESSAGE = "ADD-MESSAGE";

let store = {
  _state: {
    profilePage: {
      postData: [
        {
          id: 1,
          message: "Hi there, how are you ?",
          likeCounter: "40",
          dislikeCounter: "20",
        },
        {
          id: 2,
          message: "It`s my first post",
          likeCounter: "30",
          dislikeCounter: "10",
        },
      ],
    },

    messagesPage: {
      dialogsData: [
        { id: 1, name: "Ilya" },
        { id: 1, name: "Alexey" },
        { id: 1, name: "Sergey" },
        { id: 1, name: "Artem" },
        { id: 1, name: "Dmitriy" },
        { id: 1, name: "Vladimir" },
      ],
      messagesData: [
        { id: 1, message: "hi" },
        { id: 1, message: "how are you" },
        { id: 1, message: "nice to meet you" },
      ],
    },
  },

  getState() {
    return this._state;
  },

  addPost(postMessage) {
    let newPost = {
      id: 5,
      message: postMessage,
      likeCounter: 0,
      dislikeCounter: 0,
    };

    this._state.profilePage.postData.push(newPost);
    this.rerenderEntireTree(store);
  },

  addMessage(messageText) {
    let newMessage = {
      id: 1,
      message: messageText,
    };

    this._state.messagesPage.messagesData.push(newMessage);
    this.rerenderEntireTree(store);
  },

  rerenderEntireTree() {
    console.log("State is changed");
  },

  subscribe(observer) {
    this.rerenderEntireTree = observer;
  },

  dispatch(action) {
    switch (action.type) {
      case "ADD-POST":
        this.addPost(action.postMessage);
        break;
      case "ADD-MESSAGE":
        this.addMessage(action.messageText);
        break;
      default:
        alert("default case");
    }
  },
};

export const addPostActionCreator = (postMessage) => {
  return { type: ADD_POST, postMessage: postMessage };
};

export const addMessageActionCreator = (messageText) => {
  return { type: ADD_MESSAGE, messageText: messageText };
};

export default store;
